  });
}

return results;

// 同时提取 ckimage 和 cpimage 开头的 binary
// 只有两个前缀都存在图片时，才提取；否则不提取（binary 返回空）

const binary = $input.item.binary || {};

const hasCkimage = Object.keys(binary).some(key => key.startsWith('ckimage'));
const hasCpimage = Object.keys(binary).some(key => key.startsWith('cpimage'));

// 只有两个前缀都存在，才进行提取
if (!hasCkimage || !hasCpimage) {
  console.log('缺少 ckimage 或 cpimage 前缀的图片，不进行提取');
  return [{
    json: {
      message: "缺少 ckimage 或 cpimage 前缀的图片，不提取 binary",
      hasCkimage: hasCkimage,
      hasCpimage: hasCpimage,
      extracted: false
    },
    binary: {}   // 不返回任何 binary
  }];
}

// 两个前缀都存在，开始提取并重命名
const extractedBinary = {};

let index = 1;

// 提取 ckimage 开头的
Object.keys(binary).forEach(key => {
  if (key.startsWith('ckimage')) {
    extractedBinary[`ckimage_${index}`] = { ...binary[key] };
    index++;
  }
});

// 提取 cpimage 开头的（继续编号）
Object.keys(binary).forEach(key => {
  if (key.startsWith('cpimage')) {
    extractedBinary[`cpimage_${index}`] = { ...binary[key] };
    index++;
  }
});

console.log(`成功提取 ckimage 和 cpimage 图片，共 ${index - 1} 张`);

return [{
  json: {
    message: "成功提取 ckimage 和 cpimage 的图片",
    ckimageCount: Object.keys(binary).filter(k => k.startsWith('ckimage')).length,
    cpimageCount: Object.keys(binary).filter(k => k.startsWith('cpimage')).length,
    extracted: true
  },
  binary: extractedBinary
}];

// ================================================
// 生成任务ID和预定义路径
// 目的：在提示词生成完成后，立即返回给前端一个轮询URL
// ================================================

// 1. 生成唯一任务ID（字母和数字组合）
const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
let randomStr = '';
for (let i = 0; i < 12; i++) {
  randomStr += chars.charAt(Math.floor(Math.random() * chars.length));
}
const taskId = `${Date.now()}_${randomStr}`;

// 2. 获取上游数据
const allItems = $input.all();
const firstItem = allItems[0] || {};

// 3. 获取图片数量（从 webhook 请求中）
const imageCount = parseInt($('Webhook').first().json.body?.number) || 1;

// 4. 获取所有描述的 key（如 "1图", "2图" 等）
const descriptions = firstItem.json?.descriptions || {};
const imageKeys = Object.keys(descriptions);

// 5. 预定义图片保存路径（Docker 容器内的持久化目录）
const basePath = '/home/node/.n8n/AI-WEB/ZH_A_PLUS_images';

// 6. 你的 n8n 访问地址（前端会轮询这个地址获取图片）
const n8nHost = 'http://localhost:5678';

// 7. 构建返回给前端的图片 URL 列表
const imageUrls = imageKeys.map((key, index) => ({
  name: key,
  pollUrl: `${n8nHost}/webhook/poll-image?taskId=${taskId}&imageKey=${key}`,
  localPath: `${basePath}/${taskId}/${key}.png`
}));

// 8. 返回结果（包含所有上游数据 + 新增的 taskId 和 imageUrls）
return [{
  json: {
    ...firstItem.json,
    taskId: taskId,
    basePath: basePath,
    imageCount: imageCount,
    imageUrls: imageUrls,
    _meta: {
      generatedAt: new Date().toISOString(),
      promptReady: true,
      imageGenerating: true
    }
  },
  binary: firstItem.binary || {}
}];

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();
